import type {
  Plan,
  Recipe,
  Messages,
  SimplePlan,
  SwapSuggestionResponse,
  ApiService,
  ApiEventType,
  ApiEventCallback,
  ApiError,
  Pagination,
  PaginationParams,
  CreatePlanParams
} from '../types/api'

const API_BASE_URL = import.meta.env.VITE_API_BASE_URL as string

// Validate API_BASE_URL at module load time
if (!API_BASE_URL) {
  console.error('[MisoForMyR] VITE_API_BASE_URL environment variable is not set. API calls will fail.')
}

class RealApiService implements ApiService {
  private token: string
  private eventListeners: Map<ApiEventType, Set<ApiEventCallback>> = new Map()

  constructor(token: string) {
    this.token = token
  }

  on(event: ApiEventType, callback: ApiEventCallback): void {
    if (!this.eventListeners.has(event)) {
      this.eventListeners.set(event, new Set())
    }
    this.eventListeners.get(event)!.add(callback)
  }

  off(event: ApiEventType, callback: ApiEventCallback): void {
    const listeners = this.eventListeners.get(event)
    if (listeners) {
      listeners.delete(callback)
    }
  }

  private emit(event: ApiEventType, error?: ApiError): void {
    const listeners = this.eventListeners.get(event)
    if (listeners) {
      listeners.forEach(callback => callback(error))
    }
  }

  updateToken(token: string): void {
    this.token = token
  }

  private async request<T>(
    endpoint: string,
    options: { method?: string; headers?: Record<string, string>; body?: string } = {}
  ): Promise<T> {
    if (!API_BASE_URL) {
      throw new Error('API_BASE_URL is not configured')
    }

    const url = `${API_BASE_URL}${endpoint}`
    
    const response = await fetch(url, {
      ...options,
      headers: {
        'Authorization': `Bearer ${this.token}`,
        'Content-Type': 'application/json',
        ...options.headers
      }
    })

    if (!response.ok) {
      const apiError: ApiError = {
        status: response.status,
        message: response.statusText || `Request failed with status ${response.status}`,
        endpoint,
        method: options.method || 'GET'
      }

      // Handle 401 specifically
      if (response.status === 401) {
        this.emit('unauthenticated', apiError)
      } else {
        this.emit('apiError', apiError)
      }

      throw apiError
    }

    // For DELETE requests that return no content
    if (response.status === 204) {
      return undefined as T
    }

    return response.json()
  }

  async getPlans(params?: PaginationParams): Promise<{ data: SimplePlan[], pagination: Pagination }> {
    const query = new URLSearchParams()
    if (params?.page !== undefined) query.set('page', String(params.page))
    if (params?.page_size !== undefined) query.set('page_size', String(params.page_size))
    const qs = query.toString()
    const raw = await this.request<{ data: SimplePlan[], pagination: Pagination } | SimplePlan[]>(`/myr/plan${qs ? `?${qs}` : ''}`, {
      method: 'GET'
    })
    if (Array.isArray(raw)) {
      return { data: raw, pagination: { total: raw.length, page: 1, page_size: raw.length, has_next: false } }
    }
    return raw
  }

  async getPlan(planId: string): Promise<{ data: Plan }> {
    return this.request<{ data: Plan }>(`/myr/plan/${planId}`, {
      method: 'GET'
    })
  }

  async getSuggestedPrompts(plan: Plan | null, favorites?: string[]): Promise<{ data: string[] }> {
    const body: Record<string, unknown> = { plan }
    if (favorites !== undefined) body.favorites = favorites
    return this.request<{ data: string[] }>('/myr/prompt-suggestion', {
      method: 'POST',
      body: JSON.stringify(body)
    })
  }

  async createPlan(params: CreatePlanParams): Promise<{ data: Plan }> {
    return this.request<{ data: Plan }>('/myr/plan', {
      method: 'POST',
      body: JSON.stringify(params)
    })
  }

  async getRecipes(ids: string[]): Promise<{ data: Recipe[] }> {
    return this.request<{ data: Recipe[] }>(`/myr/recipe/?ids=${ids.join(',')}`, {
      method: 'GET'
    })
  }

  async getSwapSuggestion(planId: string, recipeIndex: number): Promise<{ data: SwapSuggestionResponse }> {
    return this.request<{ data: SwapSuggestionResponse }>(
      `/myr/plan/${planId}/swap-suggestion?recipe_index=${recipeIndex}`,
      { method: 'GET' }
    )
  }

  async updatePlanRecipes(planId: string, recipes: Recipe[]): Promise<{ data: Plan }> {
    return this.request<{ data: Plan }>(`/myr/plan/${planId}`, {
      method: 'PATCH',
      body: JSON.stringify({ recipes })
    })
  }

  async sendCompletion(planId: string, messages: Messages): Promise<{ data: Plan }> {
    return this.request<{ data: Plan }>(`/myr/plan/${planId}/completion`, {
      method: 'POST',
      body: JSON.stringify({ messages })
    })
  }

  async deletePlan(planId: string): Promise<void> {
    await this.request<void>(`/myr/plan/${planId}`, {
      method: 'DELETE'
    })
  }

  async updatePlanTitle(planId: string, title: string): Promise<{ data: Plan }> {
    return this.request<{ data: Plan }>(`/myr/plan/${planId}`, {
      method: 'PATCH',
      body: JSON.stringify({ title })
    })
  }
}

/**
 * Create a real API service instance
 * @param token Bearer token for authentication
 */
export function createApiService(token: string): ApiService {
  return new RealApiService(token)
}
