import type { MisoWidgetInstance } from '../../core/instance'
import type { Recipe, SimplePlan } from '../../types/api'
import type { PlanListingOptions } from '../../types/widget'
import { escapeHtml } from '../../utils/html'
import iconLoading from '../../imgs/icon-loading.svg'
import iconLikeActive from '../../imgs/icon-like-active.svg'
import './styles.css'

const PAGE_SIZE = 5

export class PlanListingWidget {
  private container: HTMLElement
  private instance: MisoWidgetInstance
  private options: PlanListingOptions | null
  private widgetElement: HTMLElement | null = null
  private plans: SimplePlan[] = []
  private totalPlans = 0
  private currentPage = 1
  private hasNextPage = false
  private isLoading = false
  private isLoadingMore = false
  private recentRecipes: Recipe[] = []
  private promptSuggestions: string[] = []

  constructor(container: HTMLElement, instance: MisoWidgetInstance, options?: PlanListingOptions) {
    this.container = container
    this.instance = instance
    this.options = options || null
  }

  render(): void {
    this.renderContent()
    this.loadInitialData()
  }

  private getFavorites(): string[] | undefined {
    const favorites = this.instance.getUserInfo().favoriteRecipes
    return favorites.length ? favorites : undefined
  }

  private async loadAllData(): Promise<void> {
    this.isLoading = true
    this.renderContent()

    try {
      const promises: Promise<void>[] = [this.loadPlans()]

      if (this.options?.recentFavorites?.length) {
        promises.push(this.loadRecentRecipes())
      }

      await Promise.all(promises)

      if (this.plans.length === 0) {
        await this.loadPromptSuggestions()
      }
    } catch (error) {
      console.error('Failed to load data:', error)
    } finally {
      this.isLoading = false
      this.renderContent()
    }
  }

  private async loadInitialData(): Promise<void> {
    await this.loadAllData()
  }

  private async loadPlans(): Promise<void> {
    try {
      const response = await this.instance.apiService!.getPlans({ page: 1, page_size: PAGE_SIZE })
      this.plans = response.data
      this.totalPlans = response.pagination.total
      this.hasNextPage = response.pagination.has_next
      this.currentPage = 1
    } catch (error) {
      console.error('Failed to fetch plans:', error)
      this.plans = []
      this.totalPlans = 0
      this.hasNextPage = false
    }
  }

  private async loadMorePlans(): Promise<void> {
    if (this.isLoadingMore || !this.hasNextPage) return

    this.isLoadingMore = true
    this.updateLoadMoreButton(true)

    try {
      const nextPage = this.currentPage + 1
      const response = await this.instance.apiService!.getPlans({ page: nextPage, page_size: PAGE_SIZE })
      this.plans = [...this.plans, ...response.data]
      this.totalPlans = response.pagination.total
      this.hasNextPage = response.pagination.has_next
      this.currentPage = nextPage
    } catch (error) {
      console.error('Failed to load more plans:', error)
    } finally {
      this.isLoadingMore = false
      this.renderContent()
    }
  }

  private updateLoadMoreButton(loading: boolean): void {
    const btn = this.widgetElement?.querySelector('[data-action="load-more"]') as HTMLButtonElement
    if (!btn) return
    btn.disabled = loading
    btn.textContent = loading ? 'Loading...' : 'Load More Plans'
  }

  private async loadRecentRecipes(): Promise<void> {
    try {
      const ids = (this.options?.recentFavorites || []).slice(0, 4)
      if (ids.length === 0) return
      const response = await this.instance.apiService!.getRecipes(ids)
      this.recentRecipes = (response.data || []).slice(0, 4)
    } catch (error) {
      console.error('Failed to load recent recipes:', error)
      this.recentRecipes = []
    }
  }

  private async loadPromptSuggestions(): Promise<void> {
    try {
      const response = await this.instance.apiService!.getSuggestedPrompts(null, this.getFavorites())
      this.promptSuggestions = response.data || []
    } catch (error) {
      console.error('Failed to load prompt suggestions:', error)
      this.promptSuggestions = []
    }
  }

  // ==========================================================
  // Rendering
  // ==========================================================

  private renderContent(): void {
    const template = `
      <div class="miso-plan-listing">
        <h1 class="miso-plan-listing__title">Meal Planner</h1>
        ${this.isLoading ? this.renderLoading() : this.renderBody()}
      </div>
    `

    this.container.innerHTML = template
    this.widgetElement = this.container.firstElementChild as HTMLElement

    if (!this.isLoading) {
      this.attachEventListeners()
    }
  }

  private renderLoading(): string {
    return `
      <div class="miso-plan-listing__loading">
        <img src="${iconLoading}" alt="Loading" class="miso-plan-listing__loading-icon" />
      </div>
    `
  }

  private renderBody(): string {
    const hasPlans = this.plans.length > 0
    return `
      ${this.renderSharedTop(hasPlans)}
      ${hasPlans ? this.renderNonEmptyBottom() : this.renderEmptyBottom()}
      ${this.renderFooter()}
    `
  }

  // -- Shared top section (both states) --

  private renderSharedTop(hasPlans: boolean): string {
    const heading = hasPlans ? 'Make a New Meal Plan' : 'Start Your First Meal Plan'
    return `
      <div class="miso-plan-listing__create-section">
        <div class="miso-plan-listing__hero-image"></div>
        <h2 class="miso-plan-listing__create-heading">${heading}</h2>
        <p class="miso-plan-listing__create-subheading">To get started, tell us what you want.</p>
        <div class="miso-plan-listing__input-wrapper">
          <input
            type="text"
            class="miso-plan-listing__input"
            placeholder="What meals are we planning?"
            data-action="input"
          />
        </div>
        <button class="miso-plan-listing__create-btn miso-cta-btn miso-cta-btn--cta" disabled data-action="create-plan">
          Create Meal Plan
        </button>
      </div>
      ${this.renderRecentSaves()}
    `
  }

  private renderRecentSaves(): string {
    if (this.recentRecipes.length === 0) return ''

    const cardsHtml = this.recentRecipes.map(recipe => {
      const hasImage = recipe.cover_image != null
      return `
        <div class="miso-plan-listing__recipe-card" data-recipe-id="${recipe.id}">
          <div class="miso-plan-detail__recipe-card">
            <span class="miso-plan-listing__saved-badge">
              <img src="${iconLikeActive}" alt="" />
            </span>
            <a class="miso-plan-detail__recipe-card-link" data-click-recipe="${recipe.id}">
              <div class="miso-plan-detail__recipe-image" style="${hasImage ? `background-image: url('${recipe.cover_image}')` : 'background-color: rgba(0,0,0,0.15)'}"></div>
              <div class="miso-plan-detail__recipe-title">
                <span class="miso-plan-detail__recipe-title-text">${escapeHtml(recipe.title)}</span>
              </div>
            </a>
          </div>
        </div>
      `
    }).join('')

    return `
      <div class="miso-plan-listing__divider"><span>or</span></div>
      <div class="miso-plan-listing__recent-saves">
        <p class="miso-plan-listing__section-label">Create a plan from your recent saves</p>
        <div class="miso-plan-listing__recipe-carousel">
          ${cardsHtml}
        </div>
      </div>
    `
  }

  // -- Empty state bottom --

  private renderEmptyBottom(): string {
    if (this.promptSuggestions.length === 0) return ''

    const cardsHtml = this.promptSuggestions.map((prompt, index) => `
      <div class="miso-plan-listing__prompt-card" data-prompt-index="${index}">
        ${escapeHtml(prompt)}
      </div>
    `).join('')

    return `
      <div class="miso-plan-listing__divider"><span>or</span></div>
      <div class="miso-plan-listing__prompts">
        <p class="miso-plan-listing__section-label">Get started with one of these examples</p>
        <div class="miso-plan-listing__prompt-grid">
          ${cardsHtml}
        </div>
      </div>
    `
  }

  // -- Non-empty state bottom --

  private renderNonEmptyBottom(): string {
    const countLabel = this.totalPlans === 1 ? '1' : String(this.totalPlans)

    return `
      <div class="miso-plan-listing__my-plans">
        <h2 class="miso-plan-listing__my-plans-header">My Plans <span class="counter">(${countLabel})</span></h2>
        <div class="miso-plan-listing__list">
          ${this.plans.map(plan => this.renderPlanCard(plan)).join('')}
        </div>
        ${this.hasNextPage ? `
          <button class="miso-plan-listing__load-more-btn miso-cta-btn miso-cta-btn--cta" data-action="load-more">
            Load More Plans
          </button>
        ` : ''}
      </div>
    `
  }

  private renderPlanCard(plan: SimplePlan): string {
    const recipeCount = plan.n_recipes === 1 ? '1 RECIPE' : `${plan.n_recipes} RECIPES`
    const createdDate = this.formatDate(plan.created_at)

    return `
      <div class="miso-plan-listing__card" data-plan-id="${plan.id}">
        ${this.renderRecipeImages(plan.recipes)}
        <div class="miso-plan-listing__card-content">
          <div class="miso-plan-listing__card-title">${escapeHtml(plan.title)}</div>
          <div class="miso-plan-listing__card-meta">
            <span class="miso-plan-listing__card-recipes">${recipeCount}</span>
            <div class="miso-plan-listing__card-dot-separator"></div>
            <span class="miso-plan-listing__card-date">CREATED ON ${createdDate}</span>
          </div>
        </div>
      </div>
    `
  }

  private renderRecipeImages(recipes: SimplePlan['recipes']): string {
    const displayRecipes = recipes.slice(0, 3)
    const count = displayRecipes.length

    if (count === 0) {
      return '<div class="miso-plan-listing__card-images"></div>'
    }

    const imageClass = `miso-plan-listing__card-images--${count}`

    const imagesHtml = displayRecipes
      .map((recipe, index) => {
        return `<img src="${recipe.cover_image}" alt="${escapeHtml(recipe.title)}" class="miso-plan-listing__card-image" style="z-index: ${count - index}" />`
      })
      .join('')

    return `<div class="miso-plan-listing__card-images ${imageClass}">${imagesHtml}</div>`
  }

  // -- Footer --

  private renderFooter(): string {
    return `
      <div class="miso-plan-listing__footer">
        <a class="miso-plan-listing__footer-link" data-action="learn-more">Learn more about how Meal Plans work</a>
      </div>
    `
  }

  // ==========================================================
  // Helpers
  // ==========================================================

  private formatDate(timestamp: number): string {
    const date = new Date(timestamp)
    const day = date.getDate()
    const month = date.getMonth() + 1
    const year = date.getFullYear().toString().slice(-2)
    return `${month}/${day}/${year}`
  }

  // ==========================================================
  // Event listeners
  // ==========================================================

  private attachEventListeners(): void {
    if (!this.widgetElement) return

    // Inline input + create button
    const input = this.widgetElement.querySelector('[data-action="input"]') as HTMLInputElement
    const createBtn = this.widgetElement.querySelector('[data-action="create-plan"]') as HTMLButtonElement

    if (input && createBtn) {
      input.addEventListener('input', () => {
        const hasText = input.value.trim().length > 0
        createBtn.disabled = !hasText
      })

      input.addEventListener('keydown', (e: KeyboardEvent) => {
        if (e.key === 'Enter') {
          e.preventDefault()
          this.handleCreatePlan(input)
        }
      })

      createBtn.addEventListener('click', () => {
        this.handleCreatePlan(input)
      })
    }

    // Recipe cards in recent saves carousel
    const recipeCards = this.widgetElement.querySelectorAll('[data-recipe-id]')
    recipeCards.forEach(card => {
      card.addEventListener('click', () => {
        const recipeId = (card as HTMLElement).dataset.recipeId
        if (recipeId) {
          this.instance.emit('create-plan-from-recipe', recipeId)
          if (this.options?.onCreatePlanFromRecipe) {
            this.options.onCreatePlanFromRecipe(recipeId)
          }
        }
      })
    })

    // Recipe card links in recent saves carousel
    this.widgetElement.querySelectorAll('[data-click-recipe]').forEach(el => {
      el.addEventListener('click', (e) => {
        e.preventDefault()
        e.stopPropagation()
        const recipeId = (el as HTMLElement).dataset.clickRecipe
        if (recipeId) {
          this.instance.emit('click-recipe', recipeId)
          if (this.options?.onClickRecipe) {
            this.options.onClickRecipe(recipeId)
          }
        }
      })
    })

    // Prompt cards in empty state
    const promptCards = this.widgetElement.querySelectorAll('[data-prompt-index]')
    promptCards.forEach(card => {
      card.addEventListener('click', () => {
        const promptIndex = parseInt((card as HTMLElement).dataset.promptIndex || '0', 10)
        const prompt = this.promptSuggestions[promptIndex]
        if (prompt) {
          this.instance.emit('create-plan', prompt)
          if (this.options?.onCreatePlan) {
            this.options.onCreatePlan(prompt)
          }
        }
      })
    })

    // Plan cards
    const planCards = this.widgetElement.querySelectorAll('[data-plan-id]')
    planCards.forEach(card => {
      card.addEventListener('click', () => {
        const planId = (card as HTMLElement).dataset.planId
        if (planId) {
          this.instance.emit('view-plan', planId)
          if (this.options?.onViewPlan) {
            this.options.onViewPlan(planId)
          }
        }
      })
    })

    // Load More Plans button
    const loadMoreBtn = this.widgetElement.querySelector('[data-action="load-more"]')
    if (loadMoreBtn) {
      loadMoreBtn.addEventListener('click', () => {
        this.loadMorePlans()
      })
    }

    // Learn more footer link
    const learnMoreLink = this.widgetElement.querySelector('[data-action="learn-more"]')
    if (learnMoreLink) {
      learnMoreLink.addEventListener('click', (e) => {
        e.preventDefault()
        this.instance.emit('learn-more')
        if (this.options?.onLearnMore) {
          this.options.onLearnMore()
        }
      })
    }
  }

  private handleCreatePlan(input: HTMLInputElement): void {
    const userMessage = input.value.trim()
    if (!userMessage) return

    this.instance.emit('create-plan', userMessage)
    if (this.options?.onCreatePlan) {
      this.options.onCreatePlan(userMessage)
    }
  }

  // ==========================================================
  // Public API
  // ==========================================================

  async getPlans(): Promise<SimplePlan[]> {
    return this.plans
  }

  async refreshPlans(): Promise<void> {
    await this.loadAllData()
  }

  destroy(): void {
    if (this.widgetElement) {
      this.container.removeChild(this.widgetElement)
      this.widgetElement = null
    }
    this.plans = []
    this.recentRecipes = []
    this.promptSuggestions = []
  }
}
