import type { WidgetConfig, WidgetInstance, EventCallback, PlanListingCallbacks, PlanListingOptions, PlanDetailOptions, UserInfo, TokenExpiryOptions, TokenRefreshConfig } from '../types/widget'
import type { ApiService, ApiError, SimplePlan } from '../types/api'
import { PlanListingWidget } from '../widgets/plan-listing'
import { PlanDetailWidget } from '../widgets/plan-detail'
import { createApiService } from '../services/api'
import { jwtDecode } from 'jwt-decode'

const STORAGE_KEY_PREFIX = 'misoForMyR:'
const USER_INFO_KEY = `${STORAGE_KEY_PREFIX}userInfo`

export class MisoWidgetInstance implements WidgetInstance {
  private config: WidgetConfig
  private eventListeners: Map<string, Set<EventCallback>> = new Map()
  private _planListingWidget: PlanListingWidget | null = null
  private _planDetailWidget: PlanDetailWidget | null = null
  private _planListingCallbacks: PlanListingOptions | null = null
  private _planDetailCallbacks: PlanDetailOptions | null = null
  private _userInfo: UserInfo = { favoriteRecipes: [] }
  private _checkedRecipeIds: Set<string> = new Set()
  public apiService: ApiService | null = null
  private _refreshConfig: TokenRefreshConfig | null = null
  private _tokenExpiry: number | null = null
  private _refreshTimer: ReturnType<typeof setTimeout> | null = null
  private _isRefreshing: boolean = false
  private _lastRefreshTime: number = 0
  
  constructor(config?: WidgetConfig) {
    this.config = config || { token: '' }

    // Load user info from sessionStorage
    this.loadUserInfo()

    // Initialize API service if token provided
    if (config?.token) {
      this.initApiService(config.token)
    }
  }

  private initApiService(token: string): void {
    this.config.token = token
    this.apiService = createApiService(token)

    // Bubble up API service events to widget instance
    this.apiService.on('unauthenticated', (error?: ApiError) => {
      this.emit('unauthenticated', error)
      this.invokePlanListingCallback('onUnauthenticated', error)
      this.invokePlanDetailCallback('onUnauthenticated', error)
    })

    this.apiService.on('apiError', (error?: ApiError) => {
      this.emit('apiError', error)
      this.invokePlanListingCallback('onApiError', error)
      this.invokePlanDetailCallback('onApiError', error)
    })
  }

  private loadUserInfo(): void {
    try {
      const stored = sessionStorage.getItem(USER_INFO_KEY)
      if (stored) {
        this._userInfo = JSON.parse(stored)
      }
    } catch (e) {
      console.error('Failed to load user info from sessionStorage:', e)
    }
  }

  private saveUserInfo(): void {
    try {
      sessionStorage.setItem(USER_INFO_KEY, JSON.stringify(this._userInfo))
    } catch (e) {
      console.error('Failed to save user info to sessionStorage:', e)
    }
  }

  private parseTokenExpiry(token: string): number | null {
    try {
      const decoded = jwtDecode<{ exp?: number }>(token)
      if (decoded.exp && typeof decoded.exp === 'number') {
        return decoded.exp * 1000 // Convert to milliseconds
      }
      return null
    } catch (e) {
      console.warn('[MisoForMyR] Failed to parse JWT token expiry:', e)
      return null
    }
  }

  private clearRefreshTimer(): void {
    if (this._refreshTimer) {
      clearTimeout(this._refreshTimer)
      this._refreshTimer = null
    }
  }

  private scheduleTokenRefresh(expiryMs: number): void {
    if (!this._refreshConfig) return

    const now = Date.now()
    const tokenLifetimeMs = expiryMs - now
    const proactiveWindowMs = this._refreshConfig.proactiveRefreshWindowMs ?? 120000

    // Validate token lifetime
    if (tokenLifetimeMs <= 0) {
      console.warn('[MisoForMyR] Token already expired, refreshing immediately')
      this.performTokenRefresh()
      return
    }

    // If proactive window is larger than token lifetime, use 80% of lifetime instead
    let effectiveProactiveWindow = proactiveWindowMs
    if (proactiveWindowMs >= tokenLifetimeMs) {
      effectiveProactiveWindow = Math.floor(tokenLifetimeMs * 0.2) // Refresh at 80% of lifetime
      console.warn(
        `[MisoForMyR] proactiveRefreshWindowMs (${proactiveWindowMs}ms) exceeds token lifetime (${tokenLifetimeMs}ms). ` +
        `Using 80% of token lifetime (${effectiveProactiveWindow}ms) instead.`
      )
    }

    const refreshTime = expiryMs - effectiveProactiveWindow
    const delayMs = Math.max(0, refreshTime - now)

    this.clearRefreshTimer()

    if (delayMs === 0) {
      // Within refresh window, trigger immediately
      this.performTokenRefresh()
    } else {
      this._refreshTimer = setTimeout(() => {
        this.performTokenRefresh()
      }, delayMs)
    }
  }

  private async performTokenRefresh(): Promise<void> {
    if (!this._refreshConfig) return
    if (this._isRefreshing) return

    const now = Date.now()
    const minIntervalMs = this._refreshConfig.minRefreshIntervalMs ?? 30000

    // Check minimum refresh interval
    if (now - this._lastRefreshTime < minIntervalMs) {
      console.warn('[MisoForMyR] Token refresh skipped: minimum interval not met')
      return
    }

    this._isRefreshing = true
    this._lastRefreshTime = now

    try {
      this.emit('tokenExpiring')
      const newToken = await this._refreshConfig.onTokenRequired()
      
      if (!newToken || typeof newToken !== 'string') {
        throw new Error('onTokenRequired callback must return a valid token string')
      }

      // Update token without triggering full re-initialization
      this.config.token = newToken
      if (this.apiService) {
        this.apiService.updateToken(newToken)
      }

      // Parse expiry and schedule next refresh
      this._tokenExpiry = this.parseTokenExpiry(newToken)
      if (this._tokenExpiry) {
        this.scheduleTokenRefresh(this._tokenExpiry)
      }

      this.emit('tokenRefreshed')
    } catch (e) {
      console.error('[MisoForMyR] Token refresh failed:', e)
      const apiError: ApiError = {
        status: 0,
        message: e instanceof Error ? e.message : 'Token refresh failed',
        endpoint: 'token-refresh',
        method: 'CALLBACK'
      }
      this.emit('apiError', apiError)
      this.invokePlanListingCallback('onApiError', apiError)
      this.invokePlanDetailCallback('onApiError', apiError)
      
      // Stop auto-refresh on failure
      this.clearRefreshTimer()
      this._refreshConfig = null
    } finally {
      this._isRefreshing = false
    }
  }

  // ============================================================
  // Public API - Token and User Info Management
  // ============================================================

  setAuthToken(token: string, expiryOptions?: TokenExpiryOptions, refreshConfig?: TokenRefreshConfig): WidgetInstance {
    this.initApiService(token)

    // Merge refresh config (persistent across calls unless explicitly cleared)
    if (refreshConfig) {
      this._refreshConfig = { ...this._refreshConfig, ...refreshConfig }
    }

    // Determine token expiry
    if (expiryOptions?.expiresAt) {
      // Use provided expiry (in seconds, convert to milliseconds)
      this._tokenExpiry = expiryOptions.expiresAt * 1000
    } else {
      // Parse from JWT
      this._tokenExpiry = this.parseTokenExpiry(token)
    }

    // Schedule proactive refresh if config exists and expiry is known
    if (this._refreshConfig && this._tokenExpiry) {
      this.scheduleTokenRefresh(this._tokenExpiry)
    } else if (!this._tokenExpiry && this._refreshConfig) {
      console.warn('[MisoForMyR] Token refresh configured but unable to determine token expiry')
    }

    return this
  }

  clearAuthToken(): WidgetInstance {
    this.clearRefreshTimer()
    this._refreshConfig = null
    this._tokenExpiry = null
    this._lastRefreshTime = 0
    this.destroyPlanListingWidget()
    this.destroyPlanDetailWidget()
    this.apiService = null
    this.config.token = ''
    return this
  }

  setUserInfo(info: UserInfo): WidgetInstance {
    this._userInfo = { ...this._userInfo, ...info }
    this.saveUserInfo()

    // Mark all favorite recipes as checked so we don't query them again
    info.favoriteRecipes.forEach(id => this._checkedRecipeIds.add(id))

    // Update UI if plan detail widget is rendered
    if (this._planDetailWidget) {
      this._planDetailWidget.setFavoriteRecipes(this._userInfo.favoriteRecipes)
    }
    return this
  }

  clearUserInfo(): WidgetInstance {
    this._userInfo = { favoriteRecipes: [] }
    this._checkedRecipeIds.clear()
    sessionStorage.removeItem(USER_INFO_KEY)
    
    // Update UI if plan detail widget is rendered
    if (this._planDetailWidget) {
      this._planDetailWidget.setFavoriteRecipes([])
    }
    return this
  }

  getUserInfo(): UserInfo {
    return { ...this._userInfo }
  }

  getCheckedRecipeIds(): Set<string> {
    return this._checkedRecipeIds
  }

  addToFavorites(recipeId: string): void {
    if (!this._userInfo.favoriteRecipes.includes(recipeId)) {
      this._userInfo.favoriteRecipes.push(recipeId)
      this._checkedRecipeIds.add(recipeId)
      this.saveUserInfo()
    }
  }

  removeFromFavorites(recipeId: string): void {
    const index = this._userInfo.favoriteRecipes.indexOf(recipeId)
    if (index !== -1) {
      this._userInfo.favoriteRecipes.splice(index, 1)
      this.saveUserInfo()
    }
  }

  mergeFavorites(recipeIds: string[], isFavorite: boolean[]): void {
    for (let i = 0; i < recipeIds.length; i++) {
      const recipeId = recipeIds[i]
      this._checkedRecipeIds.add(recipeId)
      
      if (isFavorite[i] && !this._userInfo.favoriteRecipes.includes(recipeId)) {
        this._userInfo.favoriteRecipes.push(recipeId)
      }
    }
    this.saveUserInfo()
  }

  // ============================================================
  // Public API - Widget Access
  // ============================================================

  get planListingWidget(): PlanListingWidget | null {
    return this._planListingWidget
  }

  get planDetailWidget(): PlanDetailWidget | null {
    return this._planDetailWidget
  }

  // ============================================================
  // Events
  // ============================================================

  on(event: string, callback: EventCallback): void {
    if (!this.eventListeners.has(event)) {
      this.eventListeners.set(event, new Set())
    }
    this.eventListeners.get(event)!.add(callback)
  }

  off(event: string, callback: EventCallback): void {
    const listeners = this.eventListeners.get(event)
    if (listeners) {
      listeners.delete(callback)
    }
  }

  emit(event: string, ...args: any[]): void {
    const listeners = this.eventListeners.get(event)
    if (listeners) {
      listeners.forEach(callback => callback(...args))
    }
  }

  // ============================================================
  // Widget Rendering
  // ============================================================

  renderPlanListingWidget(container: HTMLElement, options?: PlanListingOptions): void {
    if (!this.apiService) {
      throw new Error('Auth token not set. Call setAuthToken() before rendering widgets.')
    }

    // Destroy existing widget if any
    this.destroyPlanListingWidget()

    this._planListingCallbacks = options || null
    this._planListingWidget = new PlanListingWidget(container, this, options)
    this._planListingWidget.render()
  }

  destroyPlanListingWidget(): void {
    if (this._planListingWidget) {
      this._planListingWidget.destroy()
      this._planListingWidget = null
      this._planListingCallbacks = null
    }
  }

  renderPlanDetailWidget(container: HTMLElement, planId: string | null, options?: PlanDetailOptions): void {
    if (!this.apiService) {
      throw new Error('Auth token not set. Call setAuthToken() before rendering widgets.')
    }

    // Destroy existing widget if any
    this.destroyPlanDetailWidget()

    this._planDetailCallbacks = options || null
    this._planDetailWidget = new PlanDetailWidget(container, this, planId, options)
    this._planDetailWidget.render()
  }

  destroyPlanDetailWidget(): void {
    if (this._planDetailWidget) {
      this._planDetailWidget.destroy()
      this._planDetailWidget = null
      this._planDetailCallbacks = null
    }
  }

  // ============================================================
  // Plan Data Access
  // ============================================================

  async getPlans(): Promise<SimplePlan[]> {
    if (!this._planListingWidget) {
      return []
    }
    return this._planListingWidget.getPlans()
  }

  async refreshPlans(): Promise<void> {
    if (this._planListingWidget) {
      await this._planListingWidget.refreshPlans()
    }
  }

  getConfig(): WidgetConfig {
    return this.config
  }

  // ============================================================
  // Callback Invocation Helpers
  // ============================================================

  invokePlanListingCallback<K extends keyof PlanListingCallbacks>(
    name: K,
    ...args: Parameters<NonNullable<PlanListingCallbacks[K]>>
  ): void {
    const callback = this._planListingCallbacks?.[name]
    if (callback) {
      (callback as (...args: any[]) => void)(...args)
    }
  }

  invokePlanDetailCallback(
    name: keyof PlanDetailOptions,
    ...args: any[]
  ): void {
    const callback = this._planDetailCallbacks?.[name]
    if (callback && typeof callback === 'function') {
      (callback as (...args: any[]) => void)(...args)
    }
  }

  async checkIsInFavorite(recipeIds: string[]): Promise<void> {
    const callback = this._planDetailCallbacks?.isInFavorite
    if (!callback) return

    // Filter out already-checked recipe IDs
    const uncheckedIds = recipeIds.filter(id => !this._checkedRecipeIds.has(id))
    if (uncheckedIds.length === 0) return

    try {
      const results = await callback(uncheckedIds)
      this.mergeFavorites(uncheckedIds, results)
      
      // Update UI
      if (this._planDetailWidget) {
        this._planDetailWidget.setFavoriteRecipes(this._userInfo.favoriteRecipes)
      }
    } catch (e) {
      console.error('isInFavorite callback failed:', e)
      // Ignore errors and keep existing state
    }
  }
}
